import { useEffect, useState } from 'react';
import { AdminService } from '../../../services/api';
import { Plus, Trash2, Layers, Search } from 'lucide-react';
import { Link } from 'react-router-dom';
import toast from 'react-hot-toast';

export const AdminSeries = () => {
  const [series, setSeries] = useState<any[]>([]);
  const [search, setSearch] = useState('');

  const fetchData = async () => {
    try {
      const res: any = await AdminService.getAllSeries();
      setSeries(res.data?.data || []);
    } catch (err) { setSeries([]); }
  };

  useEffect(() => { fetchData(); }, []);

  const handleDelete = async (id: string) => {
    if (!window.confirm(`Delete Series ${id}?`)) return;
    try {
      await AdminService.deleteSeries(id);
      toast.success("Series Removed");
      fetchData();
    } catch (err) { toast.error("Delete Failed"); }
  };

  const filtered = series.filter(s => 
    (s.Series_Name || "").toLowerCase().includes(search.toLowerCase()) || 
    (s.Series_ID || "").toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex justify-between items-end">
        <div>
          <h1 className="text-4xl font-black uppercase italic text-white tracking-tighter">Archive <span className="text-primary">Series</span></h1>
          <p className="text-gray-500 font-bold uppercase text-[9px] tracking-[0.4em] mt-1">Collection Management</p>
        </div>
        <Link to="/admin/series/add" className="bg-primary text-black px-6 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest hover:bg-white transition-all shadow-lg">
          <Plus size={16} className="inline mr-1" /> Create Series
        </Link>
      </div>

      <div className="relative">
        <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-primary" size={18} />
        <input 
          placeholder="Filter by ID or Name..." 
          className="w-full bg-[#0f0f0f] border border-white/10 p-4 pl-12 rounded-2xl outline-none focus:border-primary text-white text-xs font-bold transition-all"
          onChange={(e) => setSearch(e.target.value)}
        />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {filtered.map((s: any) => (
          <div key={s._id} className="bg-[#0f0f0f] p-8 rounded-[2.5rem] border border-white/5 group transition-all hover:border-white/10">
            <div className="flex items-center gap-6 mb-6">
              <div className="w-14 h-14 bg-white/5 rounded-2xl flex items-center justify-center border border-white/10 text-primary"><Layers size={20} /></div>
              <div className="flex-1 min-w-0">
                <span className="text-[9px] text-primary font-black mb-1 block uppercase tracking-widest">{s.Series_ID}</span>
                <h4 className="font-black uppercase text-xs italic truncate text-white">{s.Series_Name || 'Untitled'}</h4>
              </div>
            </div>
            <div className="flex gap-2">
              <Link to={`/admin/series/edit/${s.Series_ID}`} className="flex-1 py-3 bg-white/5 rounded-xl font-black text-[9px] uppercase text-center text-gray-300 hover:bg-white hover:text-black transition-all">Modify</Link>
              <button onClick={() => handleDelete(s.Series_ID)} className="px-4 py-3 bg-red-500/10 text-red-500 rounded-xl hover:bg-red-500 transition-all"><Trash2 size={14}/></button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
};
